@page "/notepad"
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput" @bind:after="OnContentChanged"></textarea>
</div>

<div class="d-flex align-items-center gap-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSavedAt;
    private IJSObjectReference? jsModule;
    private System.Threading.Timer? autoSaveTimer;

    private const string StorageKeyContent = "notepad-content";
    private const string StorageKeyTimestamp = "notepad-timestamp";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Notepad.razor.js");

            var stored = await jsModule.InvokeAsync<string?>("load", StorageKeyContent);
            if (stored is not null)
            {
                content = stored;
                savedContent = stored;
            }

            var timestamp = await jsModule.InvokeAsync<string?>("load", StorageKeyTimestamp);
            if (timestamp is not null && DateTime.TryParse(timestamp, out var parsed))
            {
                lastSavedAt = parsed;
            }

            autoSaveTimer = new System.Threading.Timer(
                async _ => await InvokeAsync(AutoSave), null,
                TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));

            StateHasChanged();
        }
    }

    private async Task OnContentChanged()
    {
        bool hasUnsaved = content != savedContent;
        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("setUnsaved", hasUnsaved);
        }
    }

    private async Task AutoSave()
    {
        if (content != savedContent)
        {
            await Save();
            StateHasChanged();
        }
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Save()
    {
        if (jsModule is null) return;

        await jsModule.InvokeVoidAsync("save", StorageKeyContent, content);
        savedContent = content;
        lastSavedAt = DateTime.Now;
        await jsModule.InvokeVoidAsync("save", StorageKeyTimestamp, lastSavedAt.Value.ToString("o"));
        await jsModule.InvokeVoidAsync("setUnsaved", false);
    }

    private async Task Clear()
    {
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;

        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("remove", StorageKeyContent);
            await jsModule.InvokeVoidAsync("remove", StorageKeyTimestamp);
            await jsModule.InvokeVoidAsync("setUnsaved", false);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }

        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("dispose");
            await jsModule.DisposeAsync();
        }
    }
}

let beforeUnloadHandler = null;

export function save(key, value) {
    localStorage.setItem(key, value);
}

export function load(key) {
    return localStorage.getItem(key);
}

export function remove(key) {
    localStorage.removeItem(key);
}

export function setUnsaved(unsaved) {
    if (unsaved && !beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
        };
        window.addEventListener("beforeunload", beforeUnloadHandler);
    } else if (!unsaved && beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

export function dispose() {
    if (beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

